onClick:
{{
  (() => {
    const contactId =
      Number(selQuoContact.selectedOptionValue || 0) ||
      Number(getSelectedQuote.data?.[0]?.contact_id || 0);

    return storeValue(
      "quo_contact_mode",
      contactId ? "edit" : "add"
    )
      .then(() =>
        storeValue(
          "quo_contact_id",
          contactId || null
        )
      )
      .then(() =>
        storeValue(
          "quo_contact_customer_id",
          getSelectedQuote.data?.[0]?.customer_id || null
        )
      )
      .then(() => getQuoCustomers.run())
      .then(() => getQuoContacts.run())
      .then(() => resetWidget("mdlQuoContact", true))
      .then(() => showModal("mdlQuoContact"));
  })()
}}
